public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int[][] env = new int[n][2];
        for (int i=0; i<n; i++) { env[i][0] = sc.nextInt(); env[i][1] = sc.nextInt(); }
        Arrays.sort(env, (a, b) -> a[0] == b[0] ? b[1] - a[1] : a[0] - b[0]);
        int[] dp = new int[n];
        int len = 0;
        for (int[] e : env) {
            int index = Arrays.binarySearch(dp, 0, len, e[1]);
            if (index < 0) index = -(index + 1);
            dp[index] = e[1];
            if (index == len) len++;
        }
        System.out.println(len);
    }
}

import java.util.*;
public class Main {
    static void backtrack(int[] nums, int start) {
        if (start == nums.length) {
            for (int num : nums) System.out.print(num + " ");
            System.out.println();
            return;
        }
        for (int i = start; i < nums.length; i++) {
            swap(nums, start, i);
            backtrack(nums, start + 1);
            swap(nums, start, i);
        }
    }
    static void swap(int[] nums, int i, int j) {
        int temp = nums[i]; nums[i] = nums[j]; nums[j] = temp;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int[] nums = new int[n];
        for (int i = 0; i < n; i++) nums[i] = sc.nextInt();
        backtrack(nums, 0);
    }
}

import java.util.*;
public class Main {
    static int[][] dirs = {{0,1}, {1,0}, {0,-1}, {-1,0}};
    static int dfs(int[][] matrix, int i, int j, int[][] memo) {
        if (memo[i][j] > 0) return memo[i][j];
        int max = 1;
        for (int[] dir : dirs) {
            int x = i + dir[0], y = j + dir[1];
            if (x >= 0 && x < matrix.length && y >= 0 && y < matrix[0].length && matrix[x][y] > matrix[i][j]) {
                int len = 1 + dfs(matrix, x, y, memo);
                max = Math.max(max, len);
            }
        }
        memo[i][j] = max;
        return max;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int m = sc.nextInt(), n = sc.nextInt();
        int[][] matrix = new int[m][n];
        for (int i=0; i<m; i++) for(int j=0; j<n; j++) matrix[i][j] = sc.nextInt();
        int[][] memo = new int[m][n];
        int res = 0;
        for (int i=0; i<m; i++) {
            for (int j=0; j<n; j++) {
                res = Math.max(res, dfs(matrix, i, j, memo));
            }
        }
        System.out.println(res);
    }
}

