import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int maxDist = 0, lastPerson = -1;
        for (int i = 0; i < n; i++) {
            int seat = sc.nextInt();
            if (seat == 1) {
                if (lastPerson == -1) maxDist = i;
                else maxDist = Math.max(maxDist, (i - lastPerson) / 2);
                lastPerson = i;
            }
        }
        maxDist = Math.max(maxDist, n - 1 - lastPerson);
