public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String begin = sc.next(), end = sc.next();
        int n = sc.nextInt();
        Set<String> wordSet = new HashSet<>();
        for (int i=0; i<n; i++) wordSet.add(sc.next());
        if (!wordSet.contains(end)) { System.out.println(0); return; }
        Queue<String> q = new LinkedList<>();
        q.offer(begin);
        int level = 1;
        while (!q.isEmpty()) {
            int size = q.size();
            for (int i=0; i<size; i++) {
                String word = q.poll();
                if (word.equals(end)) { System.out.println(level); return; }
                char[] ca = word.toCharArray();
                for (int j=0; j<ca.length; j++) {
                    char orig = ca[j];
                    for (char c='a'; c<='z'; c++) {
                        ca[j] = c;
                        String next = new String(ca);
                        if (wordSet.contains(next)) {
                            wordSet.remove(next);
                            q.offer(next);
                        }
                    }
                    ca[j] = orig;
                }
            }
            level++;
        }
        System.out.println(0);
    }
}

