public class Main {
    static int backtrack(int open, int close, int max) {
        if (open == max && close == max) return 1;
        int count = 0;
        if (open < max) count += backtrack(open + 1, close, max);
        if (close < open) count += backtrack(open, close + 1, max);
        return count;
    }
