import java.util.*;
public class Main {
    static int[][] memo;
    static int[] jobs;
    static int dfs(int i, int d, int n) {
        if (d == 1) {
            int max = 0;
            for (int j = i; j < n; j++) max = Math.max(max, jobs[j]);
            return max;
        }
        if (memo[i][d] != -1) return memo[i][d];
        int res = Integer.MAX_VALUE, maxD = 0;
        for (int j = i; j < n - d + 1; j++) {
            maxD = Math.max(maxD, jobs[j]);
            res = Math.min(res, maxD + dfs(j + 1, d - 1, n));
        }
        return memo[i][d] = res;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt(), d = sc.nextInt();
        jobs = new int[n];
        for (int i=0; i<n; i++) jobs[i] = sc.nextInt();
        if (n < d) { System.out.println(-1); return; }
        memo = new int[n][d + 1];
        for (int[] row : memo) Arrays.fill(row, -1);
        System.out.println(dfs(0, d, n));
    }
}

