public class Main {
    static int[] counts;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int[] nums = new int[n];
        int[][] indexed = new int[n][2];
        for(int i=0; i<n; i++) {
            nums[i] = sc.nextInt();
            indexed[i] = new int[]{i, nums[i]};
        }
        counts = new int[n];
        mergeSort(indexed, 0, n - 1);
        for (int c : counts) System.out.print(c + " ");
    }
    static void mergeSort(int[][] arr, int left, int right) {
        if (left >= right) return;
        int mid = left + (right - left) / 2;
        mergeSort(arr, left, mid);
        mergeSort(arr, mid + 1, right);
        merge(arr, left, mid, right);
    }
    static void merge(int[][] arr, int left, int mid, int right) {
        int[][] temp = new int[right - left + 1][2];
        int i = left, j = mid + 1, k = 0, rightCount = 0;
        while (i <= mid && j <= right) {
            if (arr[i][1] <= arr[j][1]) {
                counts[arr[i][0]] += rightCount;
                temp[k++] = arr[i++];
            } else {
                rightCount++;
                temp[k++] = arr[j++];
            }
        }
        while (i <= mid) {
            counts[arr[i][0]] += rightCount;
            temp[k++] = arr[i++];
        }
        while (j <= right) temp[k++] = arr[j++];
        for (int p = 0; p < temp.length; p++) arr[left + p] = temp[p];
    }
}

