import java.util.*;
public class Main {
    static Map<String, List<String>> memo = new HashMap<>();
    static List<String> dfs(String s, Set<String> dict) {
        if (memo.containsKey(s)) return memo.get(s);
        List<String> res = new ArrayList<>();
        if (s.isEmpty()) {
            res.add("");
            return res;
        }
        for (String word : dict) {
            if (s.startsWith(word)) {
                List<String> subList = dfs(s.substring(word.length()), dict);
                for (String sub : subList) {
                    res.add(word + (sub.isEmpty() ? "" : " ") + sub);
                }
            }
        }
        memo.put(s, res);
        return res;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String s = sc.next();
        int n = sc.nextInt();
        Set<String> dict = new HashSet<>();
        for (int i = 0; i < n; i++) dict.add(sc.next());
        List<String> res = dfs(s, dict);
        for (String str : res) System.out.println(str);
    }
}

