                stack.push(c);
            } else {
                if (stack.isEmpty()) { valid = false; break; }
                char top = stack.pop();
                if ((c == ')' && top != '(') || (c == '}' && top != '{') || (c == ']' && top != '[')) {
                    valid = false; break;
                }
            }
        }
        if (!stack.isEmpty()) valid = false;
        System.out.println(valid ? "Yes" : "No");
    }
}

