                    for (char c='a'; c<='z'; c++) {
                        ca[j] = c;
                        String next = new String(ca);
                        if (wordSet.contains(next)) {
                            wordSet.remove(next);
                            q.offer(next);
                        }
                    }
                    ca[j] = orig;
                }
            }
            level++;
        }
