        while (!q.isEmpty()) {
            int curr = q.poll();
            count++;
            for (int neighbor : adj.get(curr)) {
                if (--indegree[neighbor] == 0) q.offer(neighbor);
            }
        }
        System.out.println(count == n ? "Yes" : "No");
    }
}

