import java.util.*;
public class Main {
    static int backtrack(int row, int n, Set<Integer> cols, Set<Integer> diags, Set<Integer> antiDiags) {
        if (row == n) return 1;
        int solutions = 0;
        for (int col = 0; col < n; col++) {
            int diag = row - col;
            int antiDiag = row + col;
            if (cols.contains(col) || diags.contains(diag) || antiDiags.contains(antiDiag)) continue;
            cols.add(col);
            diags.add(diag);
            antiDiags.add(antiDiag);
            solutions += backtrack(row + 1, n, cols, diags, antiDiags);
            cols.remove(col);
            diags.remove(diag);
            antiDiags.remove(antiDiag);
        }
        return solutions;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        System.out.println(backtrack(0, n, new HashSet<>(), new HashSet<>(), new HashSet<>()));
    }
}

